function escapeHtml(text) {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

export const PrintBtn = ({ label = 'Print' }) => {
  const s = useButtonStyles();
  const { isDark, setLightTheme, setDarkTheme } = useTheme();

  const handlePrint = () => {
    const wasAlreadyDark = isDark;

    // Switch React state to light mode so all components re-render with light colours
    if (wasAlreadyDark) {
      flushSync(() => setLightTheme());
    }

    // Ensure print CSS is in <head> (ToolPageWrapper also injects this on mount,
    // but this is a safety net for edge cases)
    if (!document.getElementById('db-wrapper-print-css')) {
      const style = document.createElement('style');
      style.id = 'db-wrapper-print-css';
      style.textContent = [
        '[data-print-show-flex] { display: none; }',
        '@media print {',
        '  [data-print-hide] { display: none !important; }',
        '  [data-print-show-flex] { display: flex !important; }',
        '  [data-print-grid] { display: block !important; }',
        '  [data-print-main] { grid-column: 1 / -1 !important; max-width: 100% !important; }',
        '  html, body { background: white !important; background-color: white !important; }',
        '  [data-print-wrapper] { background: white !important; background-color: white !important; }',
        '  [data-print-section], [data-print-section] > div {',
        '    background: white !important; background-color: white !important;',
        '    overflow: visible !important; border: none !important;',
        '    box-shadow: none !important; border-radius: 0 !important;',
        '  }',
        '  * { transition: none !important; animation: none !important; }',
        '}',
      ].join('\n');
      document.head.appendChild(style);
    }

    // Restore dark mode after print dialog closes
    const restore = () => {
      if (wasAlreadyDark) setDarkTheme();
      window.removeEventListener('afterprint', restore);
    };
    window.addEventListener('afterprint', restore);
    if (wasAlreadyDark) setTimeout(restore, 12000);

    window.print();
  };

  return (
    <button onClick={handlePrint} className={`${btnClass} ${s.base}`}>
      <span className="text-sm">🖨️</span> {label}
    </button>
  );
};

// ─── ActionBar ───────────────────────────────────────────────
/**
 * Combined Copy + Share + Print in one row.
 * Convenience wrapper for the common pattern.
 * 
 * Props:
 *   content       — text for Copy and Share; also used as print fallback
 *   printHtml     — optional HTML string for rich print layout with coloured panels.
 *                   When provided, replaces the default <pre> block in the print window.
 *                   The DeftBrain header/footer are still injected automatically.
 *                   Use db-panel, db-panel-success, db-panel-warning etc CSS classes.
 *   title         — used by Share and Print (default: "DeftBrain")
 *   copyLabel     — CopyBtn label (default: "Copy")
 *   printLabel    — PrintBtn label (default: "Print")
 *   printVariant  — 'full' or 'card'
 *   shareUrl      — optional URL for Share
 *   onCopied      — optional callback after copy
 *   showCopy      — show copy button (default: true)
 *   showShare     — show share button (default: true)
 *   showPrint     — show print button (default: true)
 */
export const ActionBar = ({
  content,
  resultsRef,
  title = 'DeftBrain',
  copyLabel = 'Copy',
  printLabel = 'Print',
  shareUrl,
  onCopied,
  showCopy = true,
  showShare = true,
  showPrint = true,
}) => {
  return (
    <div data-print-hide className="flex items-center gap-2">
      {showCopy && <CopyBtn content={content} label={copyLabel} onCopied={onCopied} />}
      {showShare && <ShareBtn content={content} title={title} url={shareUrl} />}
      {showPrint && <PrintBtn content={content} resultsRef={resultsRef} title={title} label={printLabel} />}
    </div>
  );
};

/**
 * textToPrintHtml — convert any plain-text result string into a styled print-ready HTML body.
 * Sections separated by \n\n---\n\n each become their own panel.
 * Lines in ALL CAPS (section headers) are styled as labels.
 * Preserves line breaks and spacing.
 *
 * Usage:
 *   import { textToPrintHtml } from '../components/ActionButtons';
 *   <ActionBar content={buildFullText()} printHtml={textToPrintHtml(buildFullText())} ... />
 */
export function textToPrintHtml(text) {
  if (!text) return null;
  // Strip trailing branding line (print footer already shows it)
  const stripped = text.replace(/\n\n— Generated by DeftBrain · deftbrain\.com\s*$/, '').trim();

  function esc(s) {
    return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  }

  function isHeader(line) {
    const t = line.trim();
    // ALL CAPS line: mostly uppercase letters/numbers/punctuation, at least 2 caps, under 80 chars
    return /^[A-Z0-9 :—–\/&()!?🔍🎯🚪💪🔗📋⚡✅⚠️🆘💡🔥🎬🕐🤫🗣️🌿]{3,}$/.test(t)
      && /[A-Z]{2}/.test(t) && t.length < 80;
  }

  // Split into sections: explicit --- dividers OR a blank line followed by an ALL CAPS header
  // Strategy: walk lines and start a new section when we hit an ALL CAPS header after content
  const lines = stripped.split('\n');
  const sections = [];
  let current = [];
  let hasContent = false;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const trimmed = line.trim();

    // Explicit --- separator
    if (trimmed === '---') {
      if (current.length) sections.push(current);
      current = [];
      hasContent = false;
      continue;
    }

    // ALL CAPS header after we've already accumulated content → new section
    if (isHeader(trimmed) && hasContent) {
      sections.push(current);
      current = [line];
      hasContent = false;
      continue;
    }

    current.push(line);
    if (trimmed) hasContent = true;
  }
  if (current.length) sections.push(current);

  function renderLines(sectionLines) {
    let html = '';
    let inList = false;

    for (const line of sectionLines) {
      const trimmed = line.trim();
      if (!trimmed) {
        if (inList) { html += '</div>'; inList = false; }
        html += '<div style="height:6px"></div>';
        continue;
      }
      if (isHeader(trimmed)) {
        if (inList) { html += '</div>'; inList = false; }
        html += `<div class="db-panel-label" style="margin-top:10px;margin-bottom:4px">${esc(trimmed)}</div>`;
        continue;
      }
      if (/^[•·\-\*]\s/.test(trimmed) || /^\d+\.\s/.test(trimmed)) {
        if (!inList) { html += '<div style="margin:4px 0">'; inList = true; }
        html += `<p style="margin:2px 0 2px 12px;line-height:1.6">${esc(trimmed)}</p>`;
        continue;
      }
      if (inList) { html += '</div>'; inList = false; }
      html += `<p style="margin:3px 0;line-height:1.7">${esc(trimmed)}</p>`;
    }
    if (inList) html += '</div>';
    return html;
  }

  // Map section header keywords → panel colour class
  function panelClass(sectionLines) {
    const header = sectionLines.find(l => l.trim()).trim().toUpperCase();
    // Danger / risk / error
    if (/DANGER|RISK|ERROR|NUCLEAR|BLOCKED|FAILED|WARNING BOX/.test(header)) return 'db-panel-danger';
    // Success / wins / good
    if (/WIN|SUCCESS|GOOD|STRENGTH|RECOMMEND|BEST MATCH|CLOSING|COMPLIMENT|POSITIVE/.test(header)) return 'db-panel-success';
    // Info / tips / notes / misconception / clarification
    if (/TIP|ADVICE|NOTE|INFO|MISCONCEPTION|CLARIFI|CONTEXT|BACKGROUND|HOW TO|QUICK START|WORKFLOW|DELIVERY|COACHING/.test(header)) return 'db-panel-info';
    // Warning / caution / mistakes / concerns / watch out
    if (/MISTAKE|AVOID|CAUTION|WATCH|CONCERN|OPENING|HOOK|EMERGENCY|FREEZE|URGENT|OVERDUE|SOON|ALERT|FLAGG/.test(header)) return 'db-panel-warning';
    return 'db-panel-neutral';
  }

  let html = '';
  sections.forEach((sectionLines, i) => {
    const body = renderLines(sectionLines);
    if (!body.trim()) return;
    const cls = panelClass(sectionLines);
    html += `<div class="db-panel ${cls}"${i > 0 ? ' style="margin-top:16px"' : ''}>`;
    html += body;
    html += '</div>';
  });
  return html || null;
}

export default { CopyBtn, ShareBtn, PrintBtn, ActionBar };
